export const monthOrder = [
    'Hindi Tithi', 'January', 'February', 'March', 'April',
    'May', 'June', 'July', 'August',
    'September', 'October', 'November', 'December'
];

export const HIGHLIGHT_DURATION_MS = 4000;
export const HIGHLIGHT_STYLES = {
    outline: '4px solid #ffd700',
    outlineOffset: '3px',
    boxShadow: '0 0 18px rgba(255,215,0,0.8)'
};
export const MS_PER_DAY = 24 * 60 * 60 * 1000;
export const SHARE_BASE_URL = 'https://rishabhkbakshi.github.io';

export const parseDate = (str: string): Date => {
    const [dayStr, monStr] = str.toLowerCase().split(/\s+/);
    const months: string[] = ['jan', 'feb', 'mar', 'apr', 'may', 'jun', 'jul', 'aug', 'sep', 'oct', 'nov', 'dec'];
    const mIdx: number = months.findIndex(m => monStr?.startsWith(m));

    return mIdx > -1 && !isNaN(Number(dayStr))
        ? new Date(new Date().getFullYear(), mIdx, Number(dayStr))
        : new Date(NaN);
};

export const normalizeToday = (): Date => {
    const today = new Date();
    today.setHours(0, 0, 0, 0);
    return today;
};

export const getDailyMessage = (messages: string[]): string => {
    const today = new Date();
    const seed = today.getDate() + today.getMonth() + today.getFullYear();
    return messages[
        seed % messages.length
    ];
};

export const flattenMembers = <T extends { children?: T[] }>(members: T[]): T[] => {
    return members.reduce<T[]>((all, member) => {
        all.push(member);
        if (member.children) {
            all.push(...flattenMembers(member.children));
        }
        return all;
    }, []);
};

export const collectFamilyEvents = (members: FamilyMember[]): CollectedEvents => {
    const births: FamilyEvent[] = [];
    const deaths: FamilyEvent[] = [];
    const anniversaries: FamilyEvent[] = [];

    const push = (event: FamilyEvent | null | undefined, target: FamilyEvent[]): void => {
        if (event) {
            target.push(event);
        }
    };

    const collect = (member: FamilyMember): void => {
        push(member.dateOfBirth ? { name: member.name, date: member.dateOfBirth, image: member.image } : null, births);
        push(member.dateOfDeath ? { name: member.name, date: member.dateOfDeath, image: member.image } : null, deaths);

        if (member.dateOfAnniversary) {
            anniversaries.push({
                name: member.spouse
                    ? `${member.name} & ${member.spouse}`
                    : member.name,
                date: member.dateOfAnniversary,
                image: member.image,
                highlightName: member.name
            });
        }

        push(
            member.spouseDateOfBirth
                ? {
                    name: member.spouse ?? '',
                    date: member.spouseDateOfBirth,
                    image: member.image,
                    highlightName: member.name
                }
                : null,
            births
        );

        push(
            member.spouseDateOfDeath
                ? {
                    name: member.spouse ?? '',
                    date: member.spouseDateOfDeath,
                    image: member.image,
                    highlightName: member.name
                }
                : null,
            deaths
        );
        member.children?.forEach(collect);
    };

    members.forEach(collect);
    return { births, deaths, anniversaries };
};

export const groupEventsByMonth = (events: FamilyEvent[]): GroupedEvents => {
    return events.reduce((grouped, event) => {
        const date = parseDate(event.date);
        const month = isNaN(date.getTime()) ? monthOrder[0] : monthOrder[date.getMonth() + 1];
        const day = isNaN(date.getTime()) ? event.date : date.getDate().toString().padStart(2, '0');

        grouped[month] ??= {};
        grouped[month][day] ??= [];
        grouped[month][day].push({
            name: event.name,
            image: event.image,
            highlightName: event.highlightName
        });

        return grouped;
    }, {} as GroupedEvents);
};

export const getNextOccurrence = (dateString: string, today: Date): Date | null => {
    const date = parseDate(dateString);
    if (isNaN(date.getTime())) {
        return null;
    }

    const occurrence = new Date(today.getFullYear(), date.getMonth(), date.getDate());
    if (occurrence < today) {
        occurrence.setFullYear(today.getFullYear() + 1);
    }

    return occurrence;
};

// ============== NAME & STRING UTILITIES ==============
/**
 * Extract short names from "John & Jane" format (e.g., "J & J")
 */
export const getShortNames = (fullName: string): string => {
    const parts = fullName.split('&');
    const first = parts[0].trim().split(' ')[0];
    const second = parts[1]?.trim().split(' ')[0] || '';
    return `${first} & ${second}`;
};

/**
 * Get display name - returns short version if contains "&", otherwise full name
 */
export const getDisplayName = (name: string): string => {
    return name.includes('&') ? getShortNames(name) : name;
};

/**
 * Get the highlight name from an item (fallback to name if no highlightName)
 */
export const getHighlightName = (item: any): string => {
    return item.highlightName || item.name;
};

/**
 * Check if any array has items
 */
export const hasAnyItems = <T>(...arrays: T[][]): boolean => {
    return arrays.some(arr => arr.length > 0);
};

// ============== IMAGE & ASSET UTILITIES ==============
/**
 * Get valid image source or default
 */
export const getImageSrc = (imageSrc: string | undefined, defaultPath: string = '/assets/images/default.png'): string => {
    return (imageSrc && imageSrc !== 'no need') ? imageSrc : defaultPath;
};

// ============== STORAGE UTILITIES ==============
/**
 * Safely get item from localStorage
 */
export const getSafeLocalStorage = (key: string, defaultValue: string = ''): string => {
    try {
        return localStorage.getItem(key) || defaultValue;
    } catch {
        return defaultValue;
    }
};

/**
 * Safely set item in localStorage
 */
export const setSafeLocalStorage = (key: string, value: string): boolean => {
    try {
        localStorage.setItem(key, value);
        return true;
    } catch {
        return false;
    }
};

/**
 * Safely parse JSON from localStorage
 */
export const getParsedLocalStorage = <T>(key: string, defaultValue: T): T => {
    try {
        const item = localStorage.getItem(key);
        return item ? JSON.parse(item) : defaultValue;
    } catch {
        return defaultValue;
    }
};

// ============== GOOGLE ANALYTICS UTILITIES ==============
declare let gtag: Function | undefined;

/**
 * Generic event tracking function
 */
export const trackEvent = (eventName: string, eventCategory: string, eventLabel?: string): void => {
    if (typeof gtag !== 'undefined') {
        gtag('event', eventName, {
            event_category: eventCategory,
            ...(eventLabel && { event_label: eventLabel })
        });
    }
};

/**
 * Track share events
 */
export const trackShareEvent = (eventType: string, name: string): void => {
    trackEvent('share_click', 'engagement', `${eventType} - ${name}`);
};

/**
 * Track navigation events
 */
export const trackNavigationEvent = (destination: string): void => {
    trackEvent(`${destination}_open`, 'navigation');
};

// ============== HIGHLIGHT & DOM UTILITIES ==============
interface HighlightOptions {
    duration?: number;
    onComplete?: () => void;
}

let currentlyHighlightedElement: HTMLElement | undefined;
let highlightTimeoutId: number | undefined;

/**
 * Apply highlight styles to an element
 */
export const highlightElement = (element: HTMLElement, options: HighlightOptions = {}): void => {
    const { duration = HIGHLIGHT_DURATION_MS, onComplete } = options;

    // Clear previous highlight
    clearHighlight();

    // Apply styles
    element.style.outline = HIGHLIGHT_STYLES.outline;
    element.style.outlineOffset = HIGHLIGHT_STYLES.outlineOffset;
    element.style.boxShadow = HIGHLIGHT_STYLES.boxShadow;

    currentlyHighlightedElement = element;

    // Auto-clear after duration
    highlightTimeoutId = window.setTimeout(() => {
        clearHighlight();
        onComplete?.();
    }, duration);
};

/**
 * Clear current highlight
 */
export const clearHighlight = (): void => {
    if (currentlyHighlightedElement) {
        currentlyHighlightedElement.style.outline = 'none';
        currentlyHighlightedElement.style.boxShadow = 'none';
        currentlyHighlightedElement = undefined;
    }
    if (highlightTimeoutId) {
        window.clearTimeout(highlightTimeoutId);
        highlightTimeoutId = undefined;
    }
};

/**
 * Find element by data-name attribute
 */
export const findElementByDataName = (name: string): HTMLElement | null => {
    const elements = document.querySelectorAll<HTMLElement>('[data-name]');
    for (let i = 0; i < elements.length; i++) {
        const el = elements[i];
        if (el.getAttribute('data-name')?.toLocaleLowerCase() === name.toLocaleLowerCase()) {
            return el;
        }
    }
    return null;
};

/**
 * Smooth scroll element into view
 */
export const smoothScrollToElement = (element: HTMLElement): void => {
    element.scrollIntoView({
        behavior: 'smooth',
        block: 'center'
    });
};

// ============== EVENT & SHARE UTILITIES ==============
/**
 * Create WhatsApp share URL
 */
export const createWhatsAppLink = (message: string): string => {
    const text = message + `\n\n👉 ${SHARE_BASE_URL}`;
    return `https://wa.me/?text=${encodeURIComponent(text)}`;
};

/**
 * Share event on WhatsApp with tracking
 */
export const shareEventOnWhatsApp = (name: string, template: string, eventType: string): void => {
    trackShareEvent(eventType, name);
    const message = template.replace('{name}', name);
    const url = createWhatsAppLink(message);
    window.open(url, '_blank');
};

// ============== EVENT COLLECTION UTILITIES ==============
/**
 * Get today's events from grouped data
 */
export const getTodayEvents = (
    groupedData: GroupedEvents,
    monthKey: string,
    dayKey: string
): NameWithImage[] => {
    return groupedData[monthKey]?.[dayKey] ?? [];
};

/**
 * Get today's formatted date string
 */
export const getTodayDateString = (today: Date): { month: string; day: string; formatted: string } => {
    const month = monthOrder[today.getMonth() + 1];
    const day = today.getDate().toString().padStart(2, '0');
    const formatted = `${month} ${today.getDate()}`;
    return { month, day, formatted };
};

/**
 * Process upcoming events
 */
export const processUpcomingEvent = (
    event: FamilyEvent,
    eventType: string,
    today: Date,
    monthOrderList: string[] = monthOrder
): UpcomingEvent | null => {
    const occurrence = getNextOccurrence(event.date, today);
    if (!occurrence) return null;

    const diffDays = Math.round((occurrence.getTime() - today.getTime()) / MS_PER_DAY);
    if (diffDays <= 0 || diffDays > 30) return null;

    return {
        ...event,
        highlightName: event.highlightName,
        type: eventType,
        timestamp: occurrence.getTime(),
        formattedDate: `${monthOrderList[occurrence.getMonth() + 1]} ${occurrence.getDate()} ${diffDays === 1 ? '(Tomorrow)' : ''}`
    };
};

/**
 * Process all upcoming events
 */
export const getUpcomingEventsGrouped = (
    births: FamilyEvent[],
    deaths: FamilyEvent[],
    anniversaries: FamilyEvent[],
    today: Date,
    monthOrderList: string[] = monthOrder
) => {
    const processEvents = (events: FamilyEvent[], type: string): UpcomingEvent[] => {
        return events
            .map(event => processUpcomingEvent(event, type, today, monthOrderList))
            .filter((event): event is UpcomingEvent => event !== null)
            .sort((a, b) => a.timestamp - b.timestamp);
    };

    return {
        birthdays: processEvents(births, '🎂'),
        remembrances: processEvents(deaths, '🕯️'),
        anniversaries: processEvents(anniversaries, '💍')
    };
};

