import { Pipe, PipeTransform } from '@angular/core';

@Pipe({
  name: 'splitDescription'
})
export class SplitDescriptionPipe implements PipeTransform {

  transform(value: string, type: string): string[] | null {
    return this.finalKidDescriptionArray(value, type);
  }

  finalKidDescriptionArray(desp: string, type: string): string[] | null {
    if (!desp) return null;

    const splitByMatch = (match: RegExpMatchArray): string[] | null => {
      if (match[1] !== undefined && match[2] !== undefined && match[3] !== undefined) {
        return [match[1].trim(), match[2].trim(), match[3].trim()];
      }

      if (match.index === undefined) return null;
      const value = match[1] || match[0];
      const start = match[1] ? (match.index + 1) : match.index;
      const end = start + value.length;
      return [
        desp.substring(0, start).trim(),
        value.trim(),
        desp.substring(end).trim(),
      ];
    };

    const patterns: Record<string, RegExp> = {
      kidDescription: /^([★\s]+)([^—]+)—(.*)$/,
      spouseDescription: /^([★\s]+)([^—]+)—(.*)$/,
      coupleDescription: /\bLate\s+[A-Z][a-z]+(?:\s+[A-Z][a-z]+)*(?:\s+ji)?(?=\s+[a-z]|[.,]|$)/,
    };

    const regex = patterns[type];
    if (!regex) return null;

    const match = desp.match(regex);
    return match ? splitByMatch(match) : [desp];
  }

}
