import { Injectable } from '@angular/core';

@Injectable({
  providedIn: 'root'
})
export class VisitCounterService {
  private readonly baseURL = 'https://countapi.mileshilliard.com';
  private readonly visitCounterKey = 'bakshi_parivar_family_tree_public_loads';

  constructor() { }

  get isItOnLocalHost(): boolean {
    return ['localhost', '127.0.0.1', ''].includes(window.location.hostname);
  }

  async getCounter(): Promise<Response> {
    return await fetch(`${this.baseURL}/api/v1/hit/${this.visitCounterKey}`);
  }

  async resetCounter(): Promise<Response> {
    return await fetch(`${this.baseURL}/api/v1/set/${this.visitCounterKey}?value=0`);
  }
}
