
import { NgModule, isDevMode } from '@angular/core';
import { BrowserModule } from '@angular/platform-browser';

import { AppRoutingModule } from './app-routing.module';
import { AppComponent } from './app.component';
import { BrowserAnimationsModule } from '@angular/platform-browser/animations';
import { FamilyTreeComponent } from './components/family-tree/family-tree.component';
import { FamilyNodeComponent } from './components/family-node/family-node.component';
import { MatTreeModule } from '@angular/material/tree';
import { MatIconModule } from '@angular/material/icon';
import { SplitDescriptionPipe } from './shared/pipes/split-description.pipe';
import { WelcomeModalComponent } from './components/welcome-modal/welcome-modal.component';
import { ServiceWorkerModule } from '@angular/service-worker';
import { HomeComponent } from './components/home/home.component';
import { FormsModule } from '@angular/forms';
import { InfoAndStatsComponent } from './components/info-and-stats/info-and-stats.component';

@NgModule({
  declarations: [
    AppComponent,
    FamilyTreeComponent,
    FamilyNodeComponent,
    SplitDescriptionPipe,
    WelcomeModalComponent,
    HomeComponent,
    InfoAndStatsComponent,
  ],
  imports: [
    FormsModule,
    BrowserModule,
    AppRoutingModule,
    BrowserAnimationsModule,
    MatTreeModule,
    MatIconModule,
    ServiceWorkerModule.register('ngsw-worker.js', {
      enabled: !isDevMode(),
      // Register the ServiceWorker as soon as the application is stable
      // or after 30 seconds (whichever comes first).
      registrationStrategy: 'registerWhenStable:30000'
    })
  ],
  providers: [],
  bootstrap: [AppComponent]
})
export class AppModule { }

