import { Component, EventEmitter, Input, OnInit, Output } from '@angular/core';
import { FamilyMember } from 'src/app/shared/allInterfaces';
import { collectFamilyEvents, flattenMembers } from 'src/app/shared/helper-functions';
import bakshiParivar from 'src/assets/data/bakshi-parivar';
import { environment } from 'src/environments/environment';

@Component({
  selector: 'app-info-and-stats',
  templateUrl: './info-and-stats.component.html',
  styleUrls: ['./info-and-stats.component.scss']
})
export class InfoAndStatsComponent implements OnInit {

  @Input('showAppInfoModal') showAppInfoModal: boolean = false;
  @Output() close = new EventEmitter<void>();

  totalMembers = 0;
  totalBirthdays = 0;
  totalAnniversaries = 0;
  totalRemembrances = 0;
  totalPhotos = 0;
  photoCoverage = 0;
  
  version = environment.appInfo.version;
  startedDate = environment.appInfo.startedDate;
  lastUpdated = environment.appInfo.lastUpdated;
  
  constructor() { }

  ngOnInit(): void {
    this.stats();
  }

  stats(): void {
    const ancestors = bakshiParivar.ancestors as FamilyMember[];

    const allMembers = flattenMembers(ancestors);

    const {
      births,
      deaths,
      anniversaries
    } = collectFamilyEvents(ancestors);

    this.totalMembers = allMembers.length;

    this.totalBirthdays = births.length;

    this.totalRemembrances = deaths.length;

    this.totalAnniversaries = anniversaries.length;

    this.totalPhotos = allMembers.filter((x: FamilyMember) => !!x.image).length;

    this.photoCoverage = Math.round(
      (this.totalPhotos / this.totalMembers) * 100
    );
  }

  closeAppInfo(): void {
    this.close.emit();
  }

}
