import { Component, ElementRef, OnInit, ViewChild } from '@angular/core';
import { NestedTreeControl } from '@angular/cdk/tree';
import { MatTreeNestedDataSource } from '@angular/material/tree';
import bakshiParivar from '../../../assets/data/bakshi-parivar';
import { FamilyEvent, FamilyMember, GroupedEvents, NameWithImage, PreviewData } from '../../shared/allInterfaces';
import { ActivatedRoute } from '@angular/router';
import {
  cleanUrlQueryParams,
  clearHighlight,
  collectFamilyEvents,
  findElementByDataName,
  getHighlightName,
  groupEventsByMonth,
  getTodayDateString,
  getTodayEvents,
  highlightElement,
  monthOrder as sharedMonthOrder,
  normalizeToday,
  smoothScrollToElement,
} from 'src/app/shared/helper-functions';

@Component({
  selector: 'app-family-tree',
  templateUrl: './family-tree.component.html',
  styleUrls: ['./family-tree.component.scss']
})
export class FamilyTreeComponent implements OnInit {
  @ViewChild('treeExportTarget') treeExportTarget?: ElementRef<HTMLElement>;

  treeControl = new NestedTreeControl<FamilyMember>(node => node.children);
  dataSource = new MatTreeNestedDataSource<FamilyMember>();

  // isLoading = true;
  previewData: PreviewData | null = null;

  activeModal: 'dob' | 'dod' | 'anniversary' | null = null;

  todayBirthdays: Array<NameWithImage> = [];
  todayRemembrances: Array<NameWithImage> = [];
  todayAnniversaries: Array<NameWithImage> = [];

  todayFormattedDate: string = '';

  groupedBirthdays: GroupedEvents = {};
  groupedDeathdays: GroupedEvents = {};
  groupedAnniversaries: GroupedEvents = {};

  private readonly monthOrder = sharedMonthOrder;

  constructor(private route: ActivatedRoute) { }

  ngOnInit(): void {

    const ancestors = bakshiParivar.ancestors as FamilyMember[];
    this.dataSource.data = ancestors;

    this.buildDateCollections();
    this.showTodayNotification();

    // ✅ existing highlight logic
    this.route.queryParams.subscribe(params => {
      const name = params['highlight'];
      if (name) {
        this.waitAndHighlight(name);
      } else {
        // ✅ NEW LOGIC (only when no highlight param)
        setTimeout(() => {
          this.autoHighlightToday();
        }, 700); // wait for DOM render
      }
    });
  }

  // ✅ BACK BUTTON
  goBack() {
    window.history.back();
  }

  autoHighlightToday() {
    const person =
      this.todayBirthdays[0] ||
      this.todayRemembrances[0] ||
      this.todayAnniversaries[0];

    if (person) {
      this.waitAndHighlight(getHighlightName(person));
    }
  }

  waitAndHighlight(name: string) {
    let attempts = 0;

    const interval = setInterval(() => {
      attempts++;
      const target = findElementByDataName(name);

      if (target) {
        smoothScrollToElement(target);
        highlightElement(target);
        cleanUrlQueryParams();
        clearInterval(interval);
      }

      if (attempts > 15) {
        clearInterval(interval);
      }
    }, 200);
  }

  showWelcomeModal = false;

  openWelcomeModal() {
    this.showWelcomeModal = true;
  }

  closeWelcomeModal() {
    this.showWelcomeModal = false;
  }

  showTodayNotification() {
    const birthdays = this.todayBirthdays.map((x: NameWithImage) => x.name);
    const remembrances = this.todayRemembrances.map((x: NameWithImage) => x.name);
    const anniversaries = this.todayAnniversaries.map((x: NameWithImage) => x.name);

    if (!birthdays.length && !remembrances.length && !anniversaries.length) return;

    let bodyParts: string[] = [];

    // ✅ Birthdays (🎂🎉)
    if (birthdays.length === 1) {
      bodyParts.push(`🎂 ${birthdays[0]} ka birthday hai`);
    } else if (birthdays.length > 1) {
      bodyParts.push(`🎉 ${birthdays[0]} aur ${birthdays.length - 1} aur logon ka birthday`);
    }

    // ✅ Remembrance (🕯️🌼)
    if (remembrances.length === 1) {
      bodyParts.push(`🕯️ ${remembrances[0]} ki punya tithi`);
    } else if (remembrances.length > 1) {
      bodyParts.push(`🌼 ${remembrances[0]} aur ${remembrances.length - 1} aur ki punya tithi`);
    }

    // ✅ Anniversaries (💍🎊)
    if (anniversaries.length === 1) {
      bodyParts.push(`💍 ${anniversaries[0]} ka aniversary hai`);
    } else if (anniversaries.length > 1) {
      bodyParts.push(`🎊 ${anniversaries[0]} aur ${anniversaries.length - 1} aur logon ka aniversary`);
    }

    const bodyText = bodyParts.join(' | ');

    // ✅ ONLY SHOW if permission already granted
    if ('Notification' in window && Notification.permission === 'granted') {
      new Notification('🙏 Bakshi Parivar Today', {
        body: bodyText
      });
    }
  }

  get modalTitle(): string {
    switch (this.activeModal) {
      case 'dob': return '🎂 All Birthdays';
      case 'dod': return '🕯️🙏 Remembrance (पुण्यतिथि)';
      case 'anniversary': return '💍 All Anniversaries';
      default: return '';
    }
  }

  private buildDateCollections(): void {
    const { births, deaths, anniversaries } = collectFamilyEvents(this.dataSource.data);

    this.groupedBirthdays = groupEventsByMonth(births);
    this.groupedDeathdays = groupEventsByMonth(deaths);
    this.groupedAnniversaries = groupEventsByMonth(anniversaries);

    this.checkTodayEvents();
  }

  private checkTodayEvents(): void {
    const today = normalizeToday();
    const { month, day, formatted } = getTodayDateString(today);

    this.todayFormattedDate = formatted;

    this.todayBirthdays = getTodayEvents(this.groupedBirthdays, month, day);
    this.todayRemembrances = getTodayEvents(this.groupedDeathdays, month, day);
    this.todayAnniversaries = getTodayEvents(this.groupedAnniversaries, month, day);
  }


  getOrderedMonths(grouped: GroupedEvents): string[] {
    return this.monthOrder.filter(month => grouped[month]);
  }

  closeDateModal(): void {
    this.activeModal = null
  }

  openDobModal(event: Event): void {
    event.stopPropagation();

    this.activeModal = 'dob';
  }

  openDodModal(event: Event): void {
    event.stopPropagation();

    this.activeModal = 'dod';
  }

  openAnniversaryModal(event: Event): void {
    event.stopPropagation();

    this.activeModal = 'anniversary';
  }

  onModalClick(event: Event): void {
    event.stopPropagation();
  }

  onMouseOver(event: MouseEvent): void {
    const target = event.target as HTMLElement;
    if (target instanceof HTMLImageElement && (target.classList.contains('node-image') || target.classList.contains('small-member-pic'))) {
      this.previewData = target.src.includes('default') ? null : { url: target.src, isSmall: target.classList.contains('small-member-pic') };
    }
  }

  onMouseOut(): void {
    this.previewData = null;
  }

  hasChild = (_: number, node: FamilyMember) => !!node.children && node.children.length > 0;
}
