import { Component, OnInit } from '@angular/core';
import { Router } from '@angular/router';

import bakshiParivar from '../../../assets/data/bakshi-parivar';
import {
  FamilyMember,
  GroupedEvents,
  NameWithImage,
  UpcomingEvent
} from '../../shared/allInterfaces';
import {
  collectFamilyEvents,
  flattenMembers,
  groupEventsByMonth,
  normalizeToday,
  getDisplayName,
  getHighlightName,
  trackByName,
  shareEventOnWhatsApp,
  getUpcomingEventsGrouped,
  getTodayEvents,
  getTodayDateString,
  hasAnyItems,
  trackNavigationEvent,
  trackEvent,
  monthOrder,
  getShortNames,
  birthdayMessages,
  remembranceMessages,
  anniversaryMessages,
  getDailyMessage
} from 'src/app/shared/helper-functions';

@Component({
  selector: 'app-home',
  templateUrl: './home.component.html',
  styleUrls: ['./home.component.scss']
})
export class HomeComponent implements OnInit {
  todayBirthdays: NameWithImage[] = [];
  todayRemembrances: NameWithImage[] = [];
  todayAnniversaries: NameWithImage[] = [];

  upcomingBirthdays: UpcomingEvent[] = [];
  upcomingRemembrances: UpcomingEvent[] = [];
  upcomingAnniversaries: UpcomingEvent[] = [];

  groupedBirthdays: GroupedEvents = {};
  groupedDeathdays: GroupedEvents = {};
  groupedAnniversaries: GroupedEvents = {};

  searchText = '';
  todayFormattedDate = '';
  allMembers: FamilyMember[] = [];
  filteredMembers: FamilyMember[] = [];

  constructor(private router: Router) { }

  ngOnInit(): void {
    const ancestors = bakshiParivar.ancestors as FamilyMember[];
    const { births, deaths, anniversaries } = collectFamilyEvents(ancestors);

    this.groupedBirthdays = groupEventsByMonth(births);
    this.groupedDeathdays = groupEventsByMonth(deaths);
    this.groupedAnniversaries = groupEventsByMonth(anniversaries);

    const upcoming = getUpcomingEventsGrouped(births, deaths, anniversaries, normalizeToday(), monthOrder);
    this.upcomingBirthdays = upcoming.birthdays;
    this.upcomingRemembrances = upcoming.remembrances;
    this.upcomingAnniversaries = upcoming.anniversaries;

    this.setTodayEvents();
    this.allMembers = flattenMembers(ancestors);
  }

  selectMember(member: FamilyMember): void {
    this.goToTreeWithHighlight(member.name);
  }

  goToTree(): void {
    trackNavigationEvent('tree');
    this.router.navigate(['/tree']);
  }

  onSearch(value: string): void {
    const searchValue = value.trim().toLowerCase();

    if (searchValue) {
      trackEvent('search_use', 'engagement', value);
    }

    this.filteredMembers = searchValue
      ? this.allMembers
        .filter(member => member.name.toLowerCase().includes(searchValue)
          || member.spouse?.toLowerCase().includes(searchValue))
        .slice(0, 5)
      : [];
  }

  goToTreeWithHighlight(name: string): void {
    this.router.navigate(['/tree'], { queryParams: { highlight: name } });
  }

  hasTodayEvents(): boolean {
    return hasAnyItems(this.todayBirthdays, this.todayRemembrances, this.todayAnniversaries);
  }

  shareBirthday(name: string): void {
    shareEventOnWhatsApp(name, getDailyMessage(birthdayMessages), 'Birthday');
  }

  shareRemembrance(name: string): void {
    shareEventOnWhatsApp(name, getDailyMessage(remembranceMessages), 'Remembrance');
  }

  shareAnniversary(name: string): void {
    shareEventOnWhatsApp(name, getDailyMessage(anniversaryMessages), 'Anniversary');
  }

  getDisplayName = getDisplayName;
  getHighlightName = getHighlightName;
  trackByName = trackByName;
  getShortNames = getShortNames;

  private setTodayEvents(): void {
    const today = normalizeToday();
    const { month, day, formatted } = getTodayDateString(today);

    this.todayFormattedDate = formatted;
    this.todayBirthdays = getTodayEvents(this.groupedBirthdays, month, day);
    this.todayRemembrances = getTodayEvents(this.groupedDeathdays, month, day);
    this.todayAnniversaries = getTodayEvents(this.groupedAnniversaries, month, day);
  }
}
