import { Component, OnInit, ViewChild } from '@angular/core';
import { trigger, transition, style, animate } from '@angular/animations';
import { FamilyTreeComponent } from './components/family-tree/family-tree.component';
import { VisitCounterService } from './shared/services/visit-counter.service';
import { InfoAndStatsComponent } from './components/info-and-stats/info-and-stats.component';
import { ActivatedRoute, Router } from '@angular/router';
import { environment } from 'src/environments/environment';

@Component({
  selector: 'app-root',
  templateUrl: './app.component.html',
  styleUrls: ['./app.component.scss'],
  animations: [
    trigger('footerAnimation', [
      transition(':enter', [
        style({ opacity: 0, transform: 'translateY(100%)' }),
        animate('800ms cubic-bezier(0.35, 0, 0.25, 1)', style({ opacity: 1, transform: 'translateY(0)' }))
      ])
    ])
  ]
})
export class AppComponent implements OnInit {
  @ViewChild(FamilyTreeComponent) familyTree?: FamilyTreeComponent;
  @ViewChild(InfoAndStatsComponent) infoAndStats?: InfoAndStatsComponent;

  title = 'bakshi-parivar';
  isDark = false;
  visitCount: number | null = null;
  visitCountError = false;
  isAdmin = false;
  // Search state for multi-match navigation
  private matches: HTMLElement[] = [];
  private currentMatchIndex = -1;
  private currentlyHighlighted?: HTMLElement;
  private highlightTimeoutId?: number;
  showNextHint = false;
  showVisitCountErrorAlert = false; // New property
  showCooldownWarning = false;
  private cooldownTimeoutId?: number;
  showHeaderSearch = false;

  isOffline = !navigator.onLine;
  showOnlineToast = false;
  private readonly SECRET_ADMIN_KEY = 'bakshi_parivar_admin_secret';
  triggerReplay = false;

  showAppInfoModal = false;

  constructor(
    private visitCounterService: VisitCounterService,
    private route: ActivatedRoute,
    private router: Router
  ) {
    this.router.events.subscribe(() => {
      this.showHeaderSearch = this.router.url.includes('tree');
    });
  }

  ngOnInit(): void {
    console.log(environment);
    
    this.onLineOffLogicInternetLogic();
    try {
      const stored = localStorage.getItem('theme');
      this.isDark = stored === 'dark';
    } catch {
      this.isDark = false;
    }
    this.applyTheme();
    void this.loadVisitCount();

    this.isAdmin = localStorage.getItem('isAdmin') === 'true';
    if (this.isAdmin) {
      return; // Already admin, no need to check query params
    }
    this.route.queryParams.subscribe(params => {
      if (params['role'] === 'admin' && params['secret'] === this.SECRET_ADMIN_KEY) {
        localStorage.setItem('isAdmin', 'true');
        localStorage.setItem('secretData', JSON.stringify({
          role: 'admin',
          secret: this.SECRET_ADMIN_KEY
        }));
        this.isAdmin = true;
        window.history.replaceState({}, '', window.location.pathname); // Remove query params from URL  
      }
    });
  }

  get isHomePage(): boolean {
    return this.router.url === '/' || this.router.url.startsWith('/?') || this.router.url === '/home';
  }

  get isTreePage(): boolean {
    return this.router.url.startsWith('/tree');
  }

  onLineOffLogicInternetLogic() {
    window.addEventListener('offline', () => {
      this.isOffline = true;
      this.showOnlineToast = false;
    });

    window.addEventListener('online', () => {
      this.isOffline = false;

      // ✅ show reconnect toast
      this.showOnlineToast = true;

      setTimeout(() => {
        this.showOnlineToast = false;
      }, 2500);   // auto hide
    });
  }

  toggleTheme(): void {
    this.isDark = !this.isDark;
    try { localStorage.setItem('theme', this.isDark ? 'dark' : 'light'); } catch { }
    this.applyTheme();
  }

  goHome(): void {
    this.router.navigate(['/']);
  }

  private applyTheme(): void {
    const cls = 'theme-dark';
    if (this.isDark) {
      document.documentElement.classList.add(cls);
    } else {
      document.documentElement.classList.remove(cls);
    }
  }

  private async handleCounterRequest(requestFn: () => Promise<Response>): Promise<number> {
    const response = await requestFn();
    if (!response.ok) {
      throw new Error('Counter request failed.');
    }

    const result = await response.json() as { value?: string; old_value?: string };
    const value = Number(result.value);

    if (!Number.isFinite(value)) {
      throw new Error('Counter response was invalid.');
    }

    if (value === 0 && 'old_value' in result) {
      const old_value = Number(result.old_value);
      console.log(`Old Visit Count = ${old_value}, Now counter is reset successfully`);
    }

    return value;
  }

  private async loadVisitCount(): Promise<void> {

    const VISIT_CACHE_KEY = 'bakshi_parivar_visit_cache';
    const LAST_VISIT_KEY = 'bakshi_parivar_last_visit';
    const OFFLINE_INC_KEY = 'bakshi_parivar_offline_inc';

    const COOLDOWN_MS = 20000;

    if (this.visitCounterService.isItOnLocalHost) {
      this.visitCount = 0;
      this.visitCountError = false;
      return;
    }

    const now = Date.now();
    const cachedCount = Number(localStorage.getItem(VISIT_CACHE_KEY) || 0);
    const offlineInc = Number(localStorage.getItem(OFFLINE_INC_KEY) || 0);

    // ✅ OFFLINE MODE
    if (!navigator.onLine) {

      // ✅ increment locally
      const newOfflineInc = offlineInc + 1;
      localStorage.setItem(OFFLINE_INC_KEY, String(newOfflineInc));

      // ✅ show combined count
      this.visitCount = cachedCount + newOfflineInc;

      return;
    }

    // ✅ show cached instantly (smooth UX)
    if (cachedCount) {
      this.visitCount = cachedCount;
    }

    const lastVisit = localStorage.getItem(LAST_VISIT_KEY);

    // ✅ COOLDOWN CHECK
    if (lastVisit && (now - Number(lastVisit) < COOLDOWN_MS)) {

      this.visitCountError = false;
      this.showCooldownWarning = true;

      this.cooldownTimeoutId = window.setTimeout(() => {
        this.showCooldownWarning = false;
        this.cooldownTimeoutId = undefined;
      }, 6000) as unknown as number;

      return;
    }

    try {

      // ✅ CALL API
      let newCount = await this.handleCounterRequest(() =>
        this.visitCounterService.getCounter()
      );

      // ✅ SYNC OFFLINE VISITS
      if (offlineInc > 0) {

        for (let i = 0; i < offlineInc; i++) {
          await this.visitCounterService.getCounter();
        }

        newCount += offlineInc;
        localStorage.setItem(OFFLINE_INC_KEY, '0');
      }

      // ✅ SAVE
      this.visitCount = newCount;
      localStorage.setItem(VISIT_CACHE_KEY, String(newCount));
      localStorage.setItem(LAST_VISIT_KEY, String(now));

      this.visitCountError = false;
      this.showVisitCountErrorAlert = false;

    } catch {

      // ✅ fallback
      this.visitCount = cachedCount + offlineInc;

      this.visitCountError = true;
      this.showVisitCountErrorAlert = true;
    }
  }

  async resetCounter(): Promise<void> {
    const currentSecret = localStorage.getItem('secretData') ?
      JSON.parse(localStorage.getItem('secretData') as string).secret : null;
    if (currentSecret !== this.SECRET_ADMIN_KEY) {
      console.error('Unauthorized attempt to reset counter.');
      this.visitCountError = true;
      this.showVisitCountErrorAlert = true; // Show alert on unauthorized attempt
      return;
    }

    try {
      this.visitCount = await this.handleCounterRequest(() => this.visitCounterService.resetCounter());
      this.visitCountError = false;
      this.showVisitCountErrorAlert = false; // Hide alert on success
    } catch {
      this.visitCountError = true;
      this.showVisitCountErrorAlert = true; // Show alert on error
    }
  }

  replayIntro(): void {
    // ✅ trigger replay via flag
    this.triggerReplay = true;

    setTimeout(() => {
      this.triggerReplay = false;
    }, 100);
  }


  onSearch(event: Event): void {
    const input = event.target as HTMLInputElement;
    const name = input.value.trim().toLowerCase();
    // Search starts after 2 characters for better responsiveness
    if (!name || name.length < 2) {
      this.clearAllHighlights();
      this.matches = [];
      this.currentMatchIndex = -1;
      this.showNextHint = false;
      return;
    }

    // Search for member cards or name labels in the DOM
    const MAX_MATCHES = 200; // safety cap
    const elements = Array.from(document.querySelectorAll<HTMLElement>('.node-card'));
    this.matches = elements.filter(el => el.textContent?.toLowerCase().includes(name)).slice(0, MAX_MATCHES);

    if (this.matches.length === 0) {
      this.clearAllHighlights();
      this.currentMatchIndex = -1;
      this.showNextHint = false;
      return;
    }

    // Start at first match and highlight it
    this.currentMatchIndex = 0;
    this.showNextHint = this.matches.length > 1;
    this.showMatch(this.currentMatchIndex);
  }

  onNextMatch(): void {
    if (!this.matches || this.matches.length === 0) return;

    // advance cyclically
    this.currentMatchIndex = (this.currentMatchIndex + 1) % this.matches.length;
    this.showMatch(this.currentMatchIndex);
  }

  private showMatch(index: number): void {
    this.clearCurrentHighlight();
    const el = this.matches[index];
    if (!el) return;
    el.scrollIntoView({ behavior: 'smooth', block: 'center', inline: 'center' });
    el.style.outline = '4px solid #ffd700';
    el.style.outlineOffset = '3px';
    el.style.boxShadow = '0 0 18px rgba(255,215,0,0.8)';
    this.currentlyHighlighted = el;

    // keep highlight for 6 seconds (between 5-7s as requested)
    this.highlightTimeoutId = window.setTimeout(() => {
      if (this.currentlyHighlighted) {
        this.currentlyHighlighted.style.outline = 'none';
        this.currentlyHighlighted = undefined;
      }
      this.highlightTimeoutId = undefined;
    }, 6000) as unknown as number;
  }

  private clearCurrentHighlight(): void {
    if (this.currentlyHighlighted) {
      this.currentlyHighlighted.style.outline = 'none';
      this.currentlyHighlighted = undefined;
    }
    if (this.highlightTimeoutId) {
      clearTimeout(this.highlightTimeoutId);
      this.highlightTimeoutId = undefined;
    }
  }

  private clearAllHighlights(): void {
    this.clearCurrentHighlight();
    document.querySelectorAll<HTMLElement>('.node-card').forEach(el => el.style.outline = 'none');
  }

  dismissCooldownWarning(): void {
    this.showCooldownWarning = false;
    if (this.cooldownTimeoutId) {
      clearTimeout(this.cooldownTimeoutId);
      this.cooldownTimeoutId = undefined;
    }
  }

  openAppInfo(): void {
    this.showAppInfoModal = true;
  }

  closeAppInfo(): void {
    this.showAppInfoModal = false;
  }
}
